commit 2508851798d727517f60d8b5a76c3001cabb7c59
Author: benwu25 <soggysocks206@gmail.com>
Date:   Thu Sep 11 19:40:17 2025 -0700

    [InstCombine] Fold `min(X+1, Y) - min(X, Y) --> zext X < Y` (#157782)

    This PR closes #157524.

    alive2: https://alive2.llvm.org/ce/z/xe_vb2
    godbolt: https://alive2.llvm.org/ce/z/7A8PxK

    This fold is invalid for `@llvm.smin.i1` since `smin(-1, 0) == -1`. I
    also avoided i1 in general since this uses zext, but it seems like those
    checks for width might not be necessary, since other folds get to it
    first.

    The alive2 proof in #157524 used a select for the fold, but it seems
    like `select X < Y, 1, 0` should be canonicalized to `zext X < Y` if the
    bit width is correct.

diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index f9155cc66031..71c53e37c775 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -2731,6 +2731,24 @@ Instruction *InstCombinerImpl::visitSub(BinaryOperator &I) {
     return BinaryOperator::CreateSub(X, Not);
   }

+  // min(X+1, Y) - min(X, Y) --> zext X < Y
+  // Replacing a sub and at least one min with an icmp
+  // and a zext is a potential improvement.
+  if (match(Op0, m_c_SMin(m_NSWAddLike(m_Value(X), m_One()), m_Value(Y))) &&
+      match(Op1, m_c_SMin(m_Specific(X), m_Specific(Y))) &&
+      I.getType()->getScalarSizeInBits() != 1 &&
+      (Op0->hasOneUse() || Op1->hasOneUse())) {
+    Value *Cond = Builder.CreateICmpSLT(X, Y);
+    return new ZExtInst(Cond, I.getType());
+  }
+  if (match(Op0, m_c_UMin(m_NUWAddLike(m_Value(X), m_One()), m_Value(Y))) &&
+      match(Op1, m_c_UMin(m_Specific(X), m_Specific(Y))) &&
+      I.getType()->getScalarSizeInBits() != 1 &&
+      (Op0->hasOneUse() || Op1->hasOneUse())) {
+    Value *Cond = Builder.CreateICmpULT(X, Y);
+    return new ZExtInst(Cond, I.getType());
+  }
+
   // Optimize pointer differences into the same array into a size.  Consider:
   //  &A[10] - &A[0]: we should compile this to "10".
   Value *LHSOp, *RHSOp;

tests.expect_optimized_program:
define i64 @test(i64 %arg0, ptr %arg1) {
  %v0 = load i64, ptr %arg1, align 8
  %v1 = icmp slt i64 %arg0, %v0
  %v3 = select i1 %v1, i64 1, i64 0
  ret i64 %v3
}
